import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const s = {
  page: { minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#0f0f1a' },
  card: { background: '#1a1a2e', padding: '2.5rem', borderRadius: '12px', width: '100%', maxWidth: '400px', border: '1px solid #2a2a4a' },
  title: { fontSize: '1.8rem', fontWeight: 700, color: '#7c6af7', marginBottom: '1.5rem', textAlign: 'center' },
  input: { width: '100%', padding: '0.75rem', marginBottom: '1rem', background: '#0f0f1a', border: '1px solid #2a2a4a', borderRadius: '8px', color: '#e0e0e0', fontSize: '1rem' },
  btn: { width: '100%', padding: '0.75rem', background: '#7c6af7', color: '#fff', border: 'none', borderRadius: '8px', fontSize: '1rem', cursor: 'pointer', fontWeight: 600 },
  err: { color: '#ff6b6b', marginBottom: '1rem', fontSize: '0.9rem' },
  link: { color: '#7c6af7', textDecoration: 'none' },
  sub: { textAlign: 'center', marginTop: '1rem', color: '#888', fontSize: '0.9rem' },
};

export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [error, setError] = useState('');
  const { register } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    try {
      await register(form.name, form.email, form.password);
      navigate('/');
    } catch (err) {
      setError(err.response?.data?.message || 'Registration failed');
    }
  };

  return (
    <div style={s.page}>
      <div style={s.card}>
        <div style={s.title}>Create Account</div>
        {error && <div style={s.err}>{error}</div>}
        <form onSubmit={handleSubmit}>
          <input style={s.input} placeholder="Name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} required />
          <input style={s.input} type="email" placeholder="Email" value={form.email} onChange={e => setForm({ ...form, email: e.target.value })} required />
          <input style={s.input} type="password" placeholder="Password (min 6 chars)" value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required minLength={6} />
          <button style={s.btn} type="submit">Register</button>
        </form>
        <div style={s.sub}>Already have an account? <Link to="/login" style={s.link}>Login</Link></div>
      </div>
    </div>
  );
}
